const messages = $input.first().json.payload || [];
const formatted = messages.map(msg => ({
  role: msg.message_type === "incoming" ? "user" : "assistant",
  content: msg.content
}));

const webhookData = $("Chatwoot Webhook").item.json.body;

return [{
  json: {
    messages: formatted,
    conversationId: webhookData.conversation.id,
    contactName: webhookData.sender.name,
    contactEmail: webhookData.sender.email,
    latestMessage: webhookData.content,
    accountId: webhookData.account.id,
    apiUrl: webhookData.account.api_url
  }
}];

options.systemMessage:
=You are a friendly sales assistant for our company. Your role is to:
1. Greet customers warmly and understand their needs
2. Qualify leads by asking about: their problem, company size, timeline, and budget
3. When a customer expresses interest in booking a call, respond with ONLY this JSON (no other text):
   {"action":"book_call","name":"[customer name]","email":"[customer email]"}
4. When a customer selects a time slot (e.g., "option 1", "Tuesday 2pm"), respond with ONLY this JSON:
   {"action":"confirm_booking","slot":"[ISO date string]"}
5. Otherwise, respond conversationally to help the customer
6. Never be pushy. If you are unsure, offer to connect them with a human agent

Customer name: {{ $json.contactName }}
Customer email: {{ $json.contactEmail }}

Previous conversation:
{{ $json.messages.map(m => m.role + ": " + m.content).join("\n") }}
